 {"id":"bd-1cnv","title":"Unit tests for NTM poll error counting and state transitions","description":"## Purpose
Comprehensive unit tests for NTM driver poll error counting and automatic state transitions when NTM becomes unavailable.

## Test File Location
`packages/agent-drivers/src/ntm/__tests__/ntm-driver.poll-errors.test.ts`

## Test Cases

### 1. Error Counter Increment
```typescript
describe("NtmDriver - poll error counting", () => {
  let driver: NtmDriver;
  let mockNtmApi: MockNtmApi;

  beforeEach(() => {
    mockNtmApi = createMockNtmApi();
    driver = new NtmDriver({ 
      ntmUrl: "http://mock-ntm",
      maxConsecutivePollErrors: 5,
      pollIntervalMs: 100,
    });
  });

  it("should increment consecutiveErrors on poll failure", async () => {
    const agentId = await driver.spawn({ task: "test" });
    mockNtmApi.setAgentResponse(agentId, { error: new Error("NTM unavailable") });

    // Trigger poll
    await driver.pollOutput(agentId);

    const session = driver.getSession(agentId);
    expect(session.consecutiveErrors).toBe(1);

    // LOGGING: Verify warning logged
    expect(mockLogger.warn).toHaveBeenCalledWith(
      expect.objectContaining({
        event: "poll_output_error",
        agentId,
        consecutiveErrors: 1,
        error: "NTM unavailable",
      })
    );
  });

  it("should increment consecutiveErrors for each failed poll", async () => {
    const agentId = await driver.spawn({ task: "test" });
    mockNtmApi.setAgentResponse(agentId, { error: new Error("timeout") });

    // 3 failed polls
    await driver.pollOutput(agentId);
    await driver.pollOutput(agentId);
    await driver.pollOutput(agentId);

    expect(driver.getSession(agentId).consecutiveErrors).toBe(3);
  });
});
```

### 2. Error Counter Reset on Success
```typescript
describe("NtmDriver - error counter reset", () => {
  it("should reset consecutiveErrors to 0 on successful poll", async () => {
    const agentId = await driver.spawn({ task: "test" });

    // Fail 3 times
    mockNtmApi.setAgentResponse(agentId, { error: new Error("fail") });
    await driver.pollOutput(agentId);
    await driver.pollOutput(agentId);
    await driver.pollOutput(agentId);
    expect(driver.getSession(agentId).consecutiveErrors).toBe(3);

    // Succeed once
    mockNtmApi.setAgentResponse(agentId, { output: "hello" });
    await driver.pollOutput(agentId);

    expect(driver.getSession(agentId).consecutiveErrors).toBe(0);
    expect(driver.getSession(agentId).lastSuccessfulPoll).toBeDefined();

    // LOGGING: Verify recovery logged
    expect(mockLogger.info).toHaveBeenCalledWith(
      expect.objectContaining({
        event: "poll_error_recovered",
        agentId,
        previousErrors: 3,
      })
    );
  });

  it("should update lastSuccessfulPoll timestamp on success", async () => {
    const agentId = await driver.spawn({ task: "test" });
    const beforePoll = Date.now();

    mockNtmApi.setAgentResponse(agentId, { output: "data" });
    await driver.pollOutput(agentId);

    const session = driver.getSession(agentId);
    expect(session.lastSuccessfulPoll.getTime()).toBeGreaterThanOrEqual(beforePoll);
  });
});
```

### 3. Threshold-Based State Transition
```typescript
describe("NtmDriver - failure threshold transition", () => {
  it("should mark agent as failed after MAX_CONSECUTIVE_ERRORS", async () => {
    const agentId = await driver.spawn({ task: "test" });
    const eventSpy = jest.fn();
    driver.on("event", eventSpy);

    mockNtmApi.setAgentResponse(agentId, { error: new Error("NTM down") });

    // Fail exactly threshold times (5)
    for (let i = 0; i < 5; i++) {
      await driver.pollOutput(agentId);
    }

    // Should have emitted terminated event
    expect(eventSpy).toHaveBeenCalledWith(
      expect.objectContaining({
        type: "terminated",
        agentId,
        reason: "error",
        error: expect.stringContaining("poll failures exceeded threshold"),
      })
    );

    // Session should be cleaned up
    expect(driver.getSession(agentId)).toBeUndefined();

    // LOGGING: Critical event logged
    expect(mockLogger.error).toHaveBeenCalledWith(
      expect.objectContaining({
        event: "poll_failure_threshold_exceeded",
        agentId,
        consecutiveErrors: 5,
        threshold: 5,
      })
    );
  });

  it("should NOT mark as failed before reaching threshold", async () => {
    const agentId = await driver.spawn({ task: "test" });
    const eventSpy = jest.fn();
    driver.on("event", eventSpy);

    mockNtmApi.setAgentResponse(agentId, { error: new Error("fail") });

    // Fail 4 times (threshold is 5)
    for (let i = 0; i < 4; i++) {
      await driver.pollOutput(agentId);
    }

    // Should NOT have terminated
    expect(eventSpy).not.toHaveBeenCalledWith(
      expect.objectContaining({ type: "terminated" })
    );
    expect(driver.getSession(agentId)).toBeDefined();
  });
});
```

### 4. Poll Interval Cleanup
```typescript
describe("NtmDriver - interval cleanup on failure", () => {
  it("should clear poll interval when agent marked failed", async () => {
    jest.useFakeTimers();
    const clearIntervalSpy = jest.spyOn(global, "clearInterval");

    const agentId = await driver.spawn({ task: "test" });
    const session = driver.getSession(agentId);
    const intervalId = session.pollInterval;

    mockNtmApi.setAgentResponse(agentId, { error: new Error("fail") });

    // Exceed threshold
    for (let i = 0; i < 5; i++) {
      await driver.pollOutput(agentId);
    }

    expect(clearIntervalSpy).toHaveBeenCalledWith(intervalId);

    // Verify no more polls happen
    const pollSpy = jest.spyOn(driver, "pollOutput");
    jest.advanceTimersByTime(1000);
    expect(pollSpy).not.toHaveBeenCalled();

    jest.useRealTimers();
  });
});
```

### 5. Stale Poll Detection
```typescript
describe("NtmDriver - stale poll detection", () => {
  it("should mark agent failed if no successful poll in MAX_POLL_STALE_MS", async () => {
    jest.useFakeTimers();

    const agentId = await driver.spawn({ task: "test" });

    // Initial successful poll
    mockNtmApi.setAgentResponse(agentId, { output: "ok" });
    await driver.pollOutput(agentId);

    // Now all polls fail but not enough to hit error threshold
    mockNtmApi.setAgentResponse(agentId, { error: new Error("slow") });

    // Advance time past stale threshold (60s)
    jest.advanceTimersByTime(61000);

    // Trigger stale check (could be via poll or health check)
    await driver.checkHealth();

    // Should be marked stale/failed
    expect(driver.getSession(agentId)).toBeUndefined();

    expect(mockLogger.warn).toHaveBeenCalledWith(
      expect.objectContaining({
        event: "agent_stale_no_successful_poll",
        agentId,
        staleDurationMs: expect.any(Number),
      })
    );

    jest.useRealTimers();
  });
});
```

### 6. Configuration Tests
```typescript
describe("NtmDriver - configuration", () => {
  it("should use custom maxConsecutivePollErrors", async () => {
    const customDriver = new NtmDriver({
      maxConsecutivePollErrors: 10,  // Custom threshold
      pollIntervalMs: 100,
    });

    const agentId = await customDriver.spawn({ task: "test" });
    mockNtmApi.setAgentResponse(agentId, { error: new Error("fail") });

    // 9 failures should not trigger transition
    for (let i = 0; i < 9; i++) {
      await customDriver.pollOutput(agentId);
    }
    expect(customDriver.getSession(agentId)).toBeDefined();

    // 10th failure should trigger
    await customDriver.pollOutput(agentId);
    expect(customDriver.getSession(agentId)).toBeUndefined();
  });
});
```

## Test Setup
```typescript
// __tests__/setup/ntm-test-utils.ts
export function createMockNtmApi() {
  const responses = new Map<string, { output?: string; error?: Error }>();
  return {
    setAgentResponse: (agentId: string, response: {...}) => {
      responses.set(agentId, response);
    },
    fetch: jest.fn(async (agentId: string) => {
      const resp = responses.get(agentId);
      if (resp?.error) throw resp.error;
      return resp?.output;
    }),
  };
}
```

## Logging Requirements
Implementation MUST emit these log events with structured data:
- `poll_output_error`: { agentId, consecutiveErrors, error, durationMs } [WARN]
- `poll_error_recovered`: { agentId, previousErrors } [INFO]
- `poll_failure_threshold_exceeded`: { agentId, consecutiveErrors, threshold } [ERROR]
- `agent_stale_no_successful_poll`: { agentId, staleDurationMs } [WARN]
- `poll_interval_cleared`: { agentId, reason } [DEBUG]

